"""
neo_tool_library.py — BlackBugsAI NEO Tool Library v2.1
Self-tools + GitHub integration + OSINT (Sherlock) + 39 built-in tools
"""
from __future__ import annotations
import os, sys, json, time, re, subprocess, sqlite3
from pathlib import Path
from typing import Optional, Callable

BASE_DIR  = Path(__file__).parent
NEO_DIR   = BASE_DIR / "neo_workspace"
TOOLS_DIR = NEO_DIR / "tools"
OSINT_DIR = NEO_DIR / "osint"

for _d in (NEO_DIR, TOOLS_DIR, OSINT_DIR):
    _d.mkdir(parents=True, exist_ok=True)


_T = {}  # name -> (description, code)

