_T['github_clone'] = (
    'Клонирует репозиторий с GitHub',
    "def run_tool(inputs):\n    import subprocess, os, shutil\n    from pathlib import Path\n    url = inputs.get('url','').strip()\n    output_dir = inputs.get('output_dir', '/tmp')\n    branch = inputs.get('branch','')\n    if not url:\n        return {'ok': False, 'output': 'Нужен url', 'files': [], 'error': 'missing'}\n    name = url.rstrip('/').split('/')[-1].replace('.git','')\n    dest = str(Path(output_dir) / name)\n    if os.path.exists(dest): shutil.rmtree(dest)\n    cmd = ['git','clone','--depth=1']\n    if branch: cmd += ['--branch', branch]\n    cmd += [url, dest]\n    def _d(b):\n        if not b: return ''\n        for e in ('utf-8','cp1251','latin-1'):\n            try: return b.decode(e)\n            except: pass\n        return b.decode('utf-8', errors='replace')\n    r = subprocess.run(cmd, capture_output=True, timeout=120)\n    out = _d(r.stdout) + _d(r.stderr)\n    if r.returncode == 0:\n        cnt = sum(1 for p in Path(dest).rglob('*') if p.is_file())\n        return {'ok': True, 'output': 'Клонировано в ' + dest + ' (' + str(cnt) + ' файлов)', 'files': [dest], 'error': ''}\n    return {'ok': False, 'output': out, 'files': [], 'error': out}"
)

