_T['pip_install'] = (
    'Устанавливает Python пакет(ы) через pip',
    "def run_tool(inputs):\n    import subprocess, sys\n    pkgs = inputs.get('packages', inputs.get('package',''))\n    if isinstance(pkgs, list): pkgs = ' '.join(pkgs)\n    pkgs = str(pkgs).strip()\n    if not pkgs:\n        return {'ok': False, 'output': 'Нужен packages', 'files': [], 'error': 'missing'}\n    def _d(b):\n        if not b: return ''\n        for e in ('utf-8','cp1251','latin-1'):\n            try: return b.decode(e)\n            except: pass\n        return b.decode('utf-8', errors='replace')\n    r = subprocess.run([sys.executable,'-m','pip','install','--break-system-packages','-q']+pkgs.split(),\n                       capture_output=True, timeout=180)\n    out = _d(r.stdout)+_d(r.stderr)\n    ok = r.returncode == 0\n    msg = ('OK: ' if ok else 'FAIL: ') + pkgs + chr(10) + out[:500]\n    return {'ok': ok, 'output': msg, 'files': [], 'error': '' if ok else out[:300]}"
)

_T['osint_sherlock'] = (
    'Sherlock OSINT — поиск аккаунтов по username на 300+ платформах (только публичные данные)',
    "def run_tool(inputs):\n    import subprocess, sys, os\n    from pathlib import Path\n    username   = inputs.get('username','').strip()\n    output_dir = inputs.get('output_dir','/tmp')\n    timeout    = int(inputs.get('timeout',120))\n    if not username:\n        return {'ok': False, 'output': 'Нужен username', 'files': [], 'error': 'missing'}\n    def _d(b):\n        if not b: return ''\n        for e in ('utf-8','cp1251','latin-1'):\n            try: return b.decode(e)\n            except: pass\n        return b.decode('utf-8', errors='replace')\n    sherlock_dir = Path(__file__).parent.parent / 'neo_workspace' / 'osint' / 'sherlock'\n    if not sherlock_dir.exists():\n        print('Устанавливаю Sherlock...')\n        r = subprocess.run(['git','clone','--depth=1',\n                            'https://github.com/sherlock-project/sherlock.git',\n                            str(sherlock_dir)], capture_output=True, timeout=120)\n        if r.returncode != 0:\n            r2 = subprocess.run([sys.executable,'-m','pip','install','sherlock-project',\n                                  '-q','--break-system-packages'], capture_output=True, timeout=180)\n            if r2.returncode != 0:\n                return {'ok': False, 'output': 'Не удалось установить Sherlock: ' + _d(r.stderr), 'files': [], 'error': 'install_failed'}\n        req = sherlock_dir / 'requirements.txt'\n        if req.exists():\n            subprocess.run([sys.executable,'-m','pip','install','-r',str(req),\n                            '-q','--break-system-packages'], capture_output=True, timeout=180)\n    out_file = Path(output_dir) / ('sherlock_' + username + '.txt')\n    entry = sherlock_dir / 'sherlock' / 'sherlock.py'\n    if not entry.exists(): entry = sherlock_dir / 'sherlock.py'\n    if entry.exists():\n        cmd = [sys.executable, str(entry), username, '--output', str(out_file), '--timeout','5','--print-found']\n    else:\n        cmd = [sys.executable,'-m','sherlock', username, '--output', str(out_file), '--timeout','5','--print-found']\n    r = subprocess.run(cmd, capture_output=True, timeout=timeout)\n    raw = _d(r.stdout) + _d(r.stderr)\n    found = [l for l in raw.splitlines() if '[+]' in l]\n    header = 'Sherlock @' + username + chr(10) + chr(10) + 'Найдено: ' + str(len(found)) + chr(10) + chr(10)\n    text = header + chr(10).join(found[:50])\n    if not found: text = text + chr(10) + raw[:500]\n    files = [str(out_file)] if out_file.exists() else []\n    return {'ok': bool(found), 'output': text, 'files': files, 'error': ''}"
)

_T['osint_username_search'] = (
    'OSINT: поиск username на популярных платформах (публичные профили)',
    "def run_tool(inputs):\n    import urllib.request\n    from pathlib import Path\n    username   = inputs.get('username','').strip()\n    output_dir = inputs.get('output_dir','/tmp')\n    if not username:\n        return {'ok': False, 'output': 'Нужен username', 'files': [], 'error': 'missing'}\n    platforms = [\n        ('GitHub',    'https://github.com/' + username),\n        ('Twitter/X', 'https://twitter.com/' + username),\n        ('Reddit',    'https://www.reddit.com/user/' + username),\n        ('TikTok',    'https://www.tiktok.com/@' + username),\n        ('YouTube',   'https://www.youtube.com/@' + username),\n        ('Twitch',    'https://www.twitch.tv/' + username),\n        ('Telegram',  'https://t.me/' + username),\n        ('GitLab',    'https://gitlab.com/' + username),\n        ('Medium',    'https://medium.com/@' + username),\n        ('Dev.to',    'https://dev.to/' + username),\n    ]\n    found = []; miss = []\n    for p, url in platforms:\n        try:\n            req = urllib.request.Request(url, headers={'User-Agent':'Mozilla/5.0'})\n            with urllib.request.urlopen(req, timeout=8) as r:\n                if r.getcode() == 200: found.append('[+] ' + p + ': ' + url)\n        except: miss.append('[-] ' + p)\n    out_file = Path(output_dir) / ('osint_u_' + username + '.txt')\n    sep = chr(10)\n    text = 'OSINT @' + username + sep + sep + sep.join(found) + sep + 'Не найдено: ' + str(len(miss))\n    out_file.write_text(text, encoding='utf-8')\n    return {'ok': bool(found), 'output': text, 'files': [str(out_file)], 'error': ''}"
)

_T['osint_site_search'] = (
    'OSINT: анализ домена — IP, HTTP заголовки, WHOIS',
    "def run_tool(inputs):\n    import urllib.request, subprocess, socket\n    from pathlib import Path\n    domain = inputs.get('domain', inputs.get('url','')).strip()\n    domain = domain.replace('https://','').replace('http://','').split('/')[0]\n    output_dir = inputs.get('output_dir','/tmp')\n    if not domain:\n        return {'ok': False, 'output': 'Нужен domain', 'files': [], 'error': 'missing'}\n    def _d(b):\n        if not b: return ''\n        for e in ('utf-8','cp1251','latin-1'):\n            try: return b.decode(e)\n            except: pass\n        return b.decode('utf-8', errors='replace')\n    sep = chr(10)\n    lines = ['OSINT Domain: ' + domain]\n    try:\n        lines.append('IP: ' + socket.gethostbyname(domain))\n    except Exception as e:\n        lines.append('DNS err: ' + str(e))\n    try:\n        req = urllib.request.Request('https://' + domain, headers={'User-Agent':'Mozilla/5.0'})\n        with urllib.request.urlopen(req, timeout=10) as r:\n            for k in ('Server','X-Powered-By','Content-Type'):\n                v = r.headers.get(k)\n                if v: lines.append(k + ': ' + v)\n    except Exception as e:\n        lines.append('HTTP: ' + str(e))\n    r = subprocess.run(['whois', domain], capture_output=True, timeout=20)\n    if r.returncode == 0: lines.append(sep + 'WHOIS:' + sep + _d(r.stdout)[:500])\n    text = sep.join(lines)\n    out_file = Path(output_dir) / ('osint_' + domain + '.txt')\n    out_file.write_text(text, encoding='utf-8')\n    return {'ok': True, 'output': text, 'files': [str(out_file)], 'error': ''}"
)

_T['python_eval'] = (
    'Выполнить Python-код в subprocess',
    "def run_tool(inputs):\n    import subprocess, sys, tempfile, os\n    code = inputs.get('code', inputs.get('script','')).strip()\n    output_dir = inputs.get('output_dir','/tmp')\n    if not code:\n        return {'ok': False, 'output': 'Нужен code', 'files': [], 'error': 'missing'}\n    def _d(b):\n        if not b: return ''\n        for e in ('utf-8','cp1251','latin-1'):\n            try: return b.decode(e)\n            except: pass\n        return b.decode('utf-8', errors='replace')\n    with tempfile.NamedTemporaryFile('w',suffix='.py',delete=False,encoding='utf-8') as f:\n        f.write(code); tmp=f.name\n    try:\n        r = subprocess.run([sys.executable,tmp], capture_output=True, timeout=30, cwd=output_dir)\n        out = _d(r.stdout)+_d(r.stderr)\n        return {'ok': r.returncode==0, 'output': out.strip()[:3000], 'files': [], 'error': _d(r.stderr) if r.returncode else ''}\n    finally:\n        try: os.unlink(tmp)\n        except: pass"
)

_T['web_scraper'] = (
    'Скачать и очистить текст с веб-страницы',
    "def run_tool(inputs):\n    import urllib.request, re\n    from pathlib import Path\n    url = inputs.get('url','').strip()\n    output_dir = inputs.get('output_dir','/tmp')\n    if not url:\n        return {'ok': False, 'output': 'Нужен url', 'files': [], 'error': 'missing'}\n    try:\n        req = urllib.request.Request(url, headers={'User-Agent':'Mozilla/5.0'})\n        with urllib.request.urlopen(req, timeout=15) as r:\n            html = r.read(100000).decode('utf-8','replace')\n        text = re.sub(r'<[^>]+>',' ',html)\n        text = re.sub(r' +',' ',text).strip()[:5000]\n        out = Path(output_dir) / ('scraped_' + str(abs(hash(url))%99999) + '.txt')\n        out.write_text(text, encoding='utf-8')\n        return {'ok': True, 'output': text[:2000], 'files': [str(out)], 'error': ''}\n    except Exception as e:\n        return {'ok': False, 'output': str(e), 'files': [], 'error': str(e)}"
)

