_T['zip_extractor'] = (
    'Извлечь содержимое ZIP-архива',
    "def run_tool(inputs):\n    import zipfile, os\n    from pathlib import Path\n    path = inputs.get('path', inputs.get('file_path','')).strip()\n    output_dir = inputs.get('output_dir','/tmp')\n    if not path or not os.path.exists(path):\n        return {'ok': False, 'output': 'Не найден: ' + path, 'files': [], 'error': 'not_found'}\n    dest = Path(output_dir) / Path(path).stem\n    dest.mkdir(parents=True, exist_ok=True)\n    with zipfile.ZipFile(path) as zf:\n        zf.extractall(str(dest))\n        names = zf.namelist()\n    files = [str(dest/n) for n in names if (dest/n).is_file()]\n    return {'ok': True, 'output': 'Извлечено ' + str(len(files)) + ' файлов в ' + str(dest), 'files': files[:20], 'error': ''}"
)

