_T['text_extractor'] = (
    'Извлечь и очистить текст из URL или файла',
    "def run_tool(inputs):\n    import urllib.request, re, os\n    from pathlib import Path\n    url  = inputs.get('url', inputs.get('link', '')).strip()\n    path = inputs.get('path', inputs.get('file_path', '')).strip()\n    output_dir = inputs.get('output_dir', '/tmp')\n    if url:\n        try:\n            req = urllib.request.Request(url, headers={'User-Agent': 'Mozilla/5.0'})\n            with urllib.request.urlopen(req, timeout=15) as r:\n                raw = r.read(200000).decode('utf-8', 'replace')\n            text = re.sub(r'<[^>]+>', ' ', raw)\n            text = re.sub(r' +', ' ', text).strip()[:8000]\n        except Exception as e:\n            return {'ok': False, 'output': str(e), 'files': [], 'error': str(e)}\n    elif path and os.path.exists(path):\n        for enc in ('utf-8', 'cp1251', 'latin-1'):\n            try: text = open(path, encoding=enc).read()[:8000]; break\n            except UnicodeDecodeError: continue\n        else: return {'ok': False, 'output': 'Не удалось декодировать', 'files': [], 'error': 'decode'}\n    else:\n        return {'ok': False, 'output': 'Нужен url или path', 'files': [], 'error': 'missing'}\n    src = url or path\n    out = Path(output_dir) / ('extracted_' + str(abs(hash(src)) % 99999) + '.txt')\n    out.write_text(text, encoding='utf-8')\n    return {'ok': True, 'output': text[:3000], 'files': [str(out)], 'error': ''}"
)

_T['http_get'] = (
    'HTTP GET запрос к API или URL',
    "def run_tool(inputs):\n    import urllib.request, urllib.parse, json as _j\n    url     = inputs.get('url', '').strip()\n    params  = inputs.get('params', inputs.get('query', {}))\n    headers = inputs.get('headers', {})\n    if not url: return {'ok': False, 'output': 'Нужен url', 'files': [], 'error': 'missing'}\n    if params and isinstance(params, dict):\n        url = url + ('&' if '?' in url else '?') + urllib.parse.urlencode(params)\n    try:\n        req = urllib.request.Request(url, headers={'User-Agent': 'Mozilla/5.0', **headers})\n        with urllib.request.urlopen(req, timeout=15) as r:\n            body = r.read(100000).decode('utf-8', 'replace')\n        try: result = _j.dumps(_j.loads(body), ensure_ascii=False, indent=2)[:4000]\n        except: result = body[:4000]\n        return {'ok': True, 'output': result, 'files': [], 'error': ''}\n    except Exception as e:\n        return {'ok': False, 'output': str(e), 'files': [], 'error': str(e)}"
)

_T['http_post'] = (
    'HTTP POST запрос к API',
    "def run_tool(inputs):\n    import urllib.request, json as _j\n    url     = inputs.get('url', '').strip()\n    data    = inputs.get('data', inputs.get('body', {}))\n    headers = inputs.get('headers', {})\n    if not url: return {'ok': False, 'output': 'Нужен url', 'files': [], 'error': 'missing'}\n    body = _j.dumps(data).encode() if isinstance(data, dict) else str(data).encode()\n    try:\n        h = {'Content-Type': 'application/json', 'User-Agent': 'Mozilla/5.0', **headers}\n        req = urllib.request.Request(url, data=body, headers=h, method='POST')\n        with urllib.request.urlopen(req, timeout=15) as r:\n            resp = r.read(100000).decode('utf-8', 'replace')\n        try: result = _j.dumps(_j.loads(resp), ensure_ascii=False, indent=2)[:4000]\n        except: result = resp[:4000]\n        return {'ok': True, 'output': result, 'files': [], 'error': ''}\n    except Exception as e:\n        return {'ok': False, 'output': str(e), 'files': [], 'error': str(e)}"
)

_T['requirements_installer'] = (
    'Установить зависимости из requirements.txt файла или списка пакетов',
    "def run_tool(inputs):\n    import subprocess, sys, os\n    from pathlib import Path\n    # Принимает файл requirements.txt или список пакетов\n    req_file = inputs.get('requirements_file', inputs.get('requirements_path', inputs.get('path', '')))\n    packages = inputs.get('packages', inputs.get('package', ''))\n    def _d(b):\n        if not b: return ''\n        for e in ('utf-8', 'cp1251', 'latin-1'):\n            try: return b.decode(e)\n            except: pass\n        return b.decode('utf-8', errors='replace')\n    if req_file and os.path.exists(str(req_file)):\n        r = subprocess.run([sys.executable, '-m', 'pip', 'install', '-r', str(req_file), '-q', '--break-system-packages'],\n                           capture_output=True, timeout=300)\n        out = _d(r.stdout) + _d(r.stderr)\n        ok = r.returncode == 0\n        return {'ok': ok, 'output': ('OK' if ok else 'FAIL') + ': ' + str(req_file) + chr(10) + out[:500], 'files': [], 'error': '' if ok else out[:300]}\n    elif packages:\n        if isinstance(packages, str): pkg_list = packages.split()\n        elif isinstance(packages, list): pkg_list = packages\n        else: pkg_list = [str(packages)]\n        r = subprocess.run([sys.executable, '-m', 'pip', 'install', '--break-system-packages', '-q'] + pkg_list,\n                           capture_output=True, timeout=300)\n        out = _d(r.stdout) + _d(r.stderr)\n        ok = r.returncode == 0\n        return {'ok': ok, 'output': ('OK' if ok else 'FAIL') + ': ' + ' '.join(pkg_list) + chr(10) + out[:500], 'files': [], 'error': '' if ok else out[:300]}\n    else:\n        return {'ok': False, 'output': 'Нужен requirements_file или packages', 'files': [], 'error': 'missing'}"
)

_T['run_script'] = (
    'Запустить Python скрипт или shell-команду',
    "def run_tool(inputs):\n    import subprocess, sys, tempfile, os\n    script   = inputs.get('script', inputs.get('code', inputs.get('cmd', ''))).strip()\n    lang     = inputs.get('lang', 'python').lower()\n    cwd      = inputs.get('cwd', inputs.get('workdir', ''))\n    timeout  = int(inputs.get('timeout', 60))\n    output_dir = inputs.get('output_dir', '/tmp')\n    if not script: return {'ok': False, 'output': 'Нужен script', 'files': [], 'error': 'missing'}\n    def _d(b):\n        if not b: return ''\n        for e in ('utf-8', 'cp1251', 'latin-1'):\n            try: return b.decode(e)\n            except: pass\n        return b.decode('utf-8', errors='replace')\n    if lang in ('sh', 'bash', 'shell'):\n        r = subprocess.run(script, shell=True, capture_output=True, timeout=timeout, cwd=cwd or output_dir)\n        out = (_d(r.stdout) + _d(r.stderr)).strip()\n        return {'ok': r.returncode == 0, 'output': out[:3000], 'files': [], 'error': out[:500] if r.returncode else ''}\n    else:\n        with tempfile.NamedTemporaryFile('w', suffix='.py', delete=False, encoding='utf-8') as f:\n            f.write(script); tmp = f.name\n        try:\n            r = subprocess.run([sys.executable, tmp], capture_output=True, timeout=timeout, cwd=cwd or output_dir)\n            out = (_d(r.stdout) + _d(r.stderr)).strip()\n            return {'ok': r.returncode == 0, 'output': out[:3000], 'files': [], 'error': _d(r.stderr) if r.returncode else ''}\n        finally:\n            try: os.unlink(tmp)\n            except: pass"
)

_T['git_info'] = (
    'Получить информацию о Git репозитории или клонировать',
    "def run_tool(inputs):\n    import subprocess, os\n    from pathlib import Path\n    url    = inputs.get('url', inputs.get('repo', '')).strip()\n    action = inputs.get('action', 'info').lower()\n    cwd    = inputs.get('path', inputs.get('cwd', '.'))\n    output_dir = inputs.get('output_dir', '/tmp')\n    def _d(b):\n        if not b: return ''\n        for e in ('utf-8', 'cp1251', 'latin-1'):\n            try: return b.decode(e)\n            except: pass\n        return b.decode('utf-8', errors='replace')\n    if action == 'clone' and url:\n        name = url.rstrip('/').split('/')[-1].replace('.git', '')\n        dest = str(Path(output_dir) / name)\n        r = subprocess.run(['git', 'clone', '--depth=1', url, dest], capture_output=True, timeout=120)\n        out = _d(r.stdout) + _d(r.stderr)\n        return {'ok': r.returncode == 0, 'output': out, 'files': [dest] if r.returncode == 0 else [], 'error': '' if r.returncode == 0 else out}\n    elif url and 'github.com' in url:\n        import urllib.request, json as _j\n        try:\n            parts = url.rstrip('/').replace('https://github.com/', '').split('/')\n            api = 'https://api.github.com/repos/' + '/'.join(parts[:2])\n            req = urllib.request.Request(api, headers={'User-Agent': 'Mozilla/5.0'})\n            with urllib.request.urlopen(req, timeout=10) as resp:\n                info = _j.loads(resp.read())\n            out = 'Репо: ' + info.get('full_name', '') + chr(10) + 'Stars: ' + str(info.get('stargazers_count', 0)) + chr(10) + info.get('description', '')\n            return {'ok': True, 'output': out, 'files': [], 'error': ''}\n        except Exception as e:\n            return {'ok': False, 'output': str(e), 'files': [], 'error': str(e)}\n    else:\n        r = subprocess.run(['git', 'log', '--oneline', '-10'], capture_output=True, timeout=10, cwd=cwd)\n        out = _d(r.stdout) + _d(r.stderr)\n        return {'ok': r.returncode == 0, 'output': out[:2000], 'files': [], 'error': ''}"
)

_T['rss_parser'] = (
    'Парсинг RSS/Atom лент',
    "def run_tool(inputs):\n    import urllib.request, re\n    from pathlib import Path\n    url = inputs.get('url', '').strip()\n    limit = int(inputs.get('limit', 10))\n    output_dir = inputs.get('output_dir', '/tmp')\n    if not url: return {'ok': False, 'output': 'Нужен url', 'files': [], 'error': 'missing'}\n    try:\n        req = urllib.request.Request(url, headers={'User-Agent': 'Mozilla/5.0'})\n        with urllib.request.urlopen(req, timeout=15) as r:\n            xml = r.read(200000).decode('utf-8', 'replace')\n        items = re.findall(r'<item[^>]*>(.*?)</item>', xml, re.DOTALL)\n        if not items: items = re.findall(r'<entry[^>]*>(.*?)</entry>', xml, re.DOTALL)\n        results = []\n        for item in items[:limit]:\n            title = re.search(r'<title[^>]*>(.*?)</title>', item, re.DOTALL)\n            link  = re.search(r'<link[^>]*>(.*?)</link>',  item, re.DOTALL)\n            desc  = re.search(r'<description[^>]*>(.*?)</description>', item, re.DOTALL)\n            t = re.sub(r'<[^>]+>', '', title.group(1) if title else '').strip()\n            l = re.sub(r'<[^>]+>', '', link.group(1)  if link  else '').strip()\n            d = re.sub(r'<[^>]+>', '', desc.group(1)  if desc  else '').strip()[:200]\n            results.append(t + chr(10) + l + chr(10) + d)\n        text = chr(10) + '---' + chr(10) + chr(10).join(results)\n        out_file = Path(output_dir) / ('rss_' + str(abs(hash(url)) % 99999) + '.txt')\n        out_file.write_text(text, encoding='utf-8')\n        return {'ok': bool(results), 'output': text[:3000], 'files': [str(out_file)], 'error': ''}\n    except Exception as e:\n        return {'ok': False, 'output': str(e), 'files': [], 'error': str(e)}"
)

_T['csv_reader'] = (
    'Читать CSV файл',
    "def run_tool(inputs):\n    import csv, json as _j, os\n    path  = inputs.get('path', inputs.get('file_path', '')).strip()\n    limit = int(inputs.get('limit', 100))\n    if not path or not os.path.exists(path):\n        return {'ok': False, 'output': 'Не найден: ' + path, 'files': [], 'error': 'not_found'}\n    try:\n        rows = []\n        for enc in ('utf-8', 'cp1251', 'latin-1'):\n            try:\n                with open(path, encoding=enc, newline='') as f:\n                    rows = list(csv.DictReader(f))[:limit]\n                break\n            except UnicodeDecodeError: continue\n        out = _j.dumps(rows[:10], ensure_ascii=False, indent=2)\n        return {'ok': True, 'output': 'Строк: ' + str(len(rows)) + chr(10) + out[:3000], 'files': [path], 'error': ''}\n    except Exception as e:\n        return {'ok': False, 'output': str(e), 'files': [], 'error': str(e)}"
)

_T['csv_writer'] = (
    'Записать данные в CSV файл',
    "def run_tool(inputs):\n    import csv, json as _j, os\n    from pathlib import Path\n    data   = inputs.get('data', inputs.get('rows', []))\n    path   = inputs.get('path', '')\n    output_dir = inputs.get('output_dir', '/tmp')\n    if not path: path = str(Path(output_dir) / 'output.csv')\n    if isinstance(data, str):\n        try: data = _j.loads(data)\n        except: return {'ok': False, 'output': 'data должен быть список', 'files': [], 'error': 'invalid_data'}\n    if not isinstance(data, list) or not data:\n        return {'ok': False, 'output': 'Нужен непустой список data', 'files': [], 'error': 'empty'}\n    os.makedirs(os.path.dirname(os.path.abspath(path)), exist_ok=True)\n    fields = list(data[0].keys()) if isinstance(data[0], dict) else list(range(len(data[0])))\n    with open(path, 'w', newline='', encoding='utf-8') as f:\n        if isinstance(data[0], dict):\n            w = csv.DictWriter(f, fieldnames=fields); w.writeheader(); w.writerows(data)\n        else:\n            csv.writer(f).writerows(data)\n    return {'ok': True, 'output': 'Записано строк: ' + str(len(data)) + ' -> ' + path, 'files': [path], 'error': ''}"
)

_T['json_transformer'] = (
    'Преобразовать JSON данные',
    "def run_tool(inputs):\n    import json as _j, os\n    from pathlib import Path\n    data    = inputs.get('data', inputs.get('json', ''))\n    action  = inputs.get('action', 'pretty').lower()\n    key     = inputs.get('key', inputs.get('field', ''))\n    output_dir = inputs.get('output_dir', '/tmp')\n    if isinstance(data, str):\n        try: data = _j.loads(data)\n        except Exception as e: return {'ok': False, 'output': 'Ошибка парсинга JSON: ' + str(e), 'files': [], 'error': str(e)}\n    if action == 'extract' and key:\n        if isinstance(data, list): result = [item.get(key) for item in data if isinstance(item, dict)]\n        else: result = data.get(key)\n    elif action == 'keys' and isinstance(data, (dict, list)):\n        result = list(data[0].keys()) if isinstance(data, list) and data else list(data.keys()) if isinstance(data, dict) else []\n    elif action == 'count':\n        result = len(data) if isinstance(data, (list, dict)) else 1\n    else:\n        result = data\n    out_str = _j.dumps(result, ensure_ascii=False, indent=2)\n    out_file = Path(output_dir) / 'transformed.json'\n    out_file.write_text(out_str, encoding='utf-8')\n    return {'ok': True, 'output': out_str[:3000], 'files': [str(out_file)], 'error': ''}"
)

_T['pdf_reader'] = (
    'Читать PDF файл',
    'def run_tool(inputs):\n    import subprocess, sys, os\n    from pathlib import Path\n    path = inputs.get(\'path\', inputs.get(\'file_path\', \'\')).strip()\n    output_dir = inputs.get(\'output_dir\', \'/tmp\')\n    if not path or not os.path.exists(path):\n        return {\'ok\': False, \'output\': \'Не найден: \' + path, \'files\': [], \'error\': \'not_found\'}\n    def _d(b):\n        if not b: return \'\'\n        for e in (\'utf-8\', \'cp1251\', \'latin-1\'):\n            try: return b.decode(e)\n            except: pass\n        return b.decode(\'utf-8\', errors=\'replace\')\n    try:\n        r = subprocess.run([sys.executable, \'-c\',\n            \'import sys; from pypdf import PdfReader; p=PdfReader(sys.argv[1]); print(chr(10).join(pg.extract_text() or "" for pg in p.pages[:10]))\',\n            path], capture_output=True, timeout=30)\n        if r.returncode == 0 and r.stdout:\n            text = _d(r.stdout)[:5000]\n            out = Path(output_dir) / (Path(path).stem + \'.txt\')\n            out.write_text(text, encoding=\'utf-8\')\n            return {\'ok\': True, \'output\': text[:3000], \'files\': [str(out)], \'error\': \'\'}\n    except: pass\n    # Fallback: pdfminer\n    try:\n        r2 = subprocess.run([sys.executable, \'-c\',\n            \'from pdfminer.high_level import extract_text; print(extract_text("\' + path + \'")[:5000])\'],\n            capture_output=True, timeout=30)\n        text = _d(r2.stdout)[:5000]\n        if text.strip():\n            out = Path(output_dir) / (Path(path).stem + \'.txt\')\n            out.write_text(text, encoding=\'utf-8\')\n            return {\'ok\': True, \'output\': text[:3000], \'files\': [str(out)], \'error\': \'\'}\n    except: pass\n    return {\'ok\': False, \'output\': \'PDF читалка недоступна. Установи: pip install pypdf\', \'files\': [], \'error\': \'no_pdf_lib\'}'
)

_T['file_search'] = (
    'Поиск файлов по имени или расширению',
    "def run_tool(inputs):\n    import os, fnmatch\n    search_dir = inputs.get('dir', inputs.get('path', '.')).strip()\n    pattern    = inputs.get('pattern', inputs.get('name', '*')).strip()\n    ext        = inputs.get('ext', '').strip().lstrip('.')\n    if ext and not pattern.endswith('.' + ext): pattern = '*.' + ext\n    results = []\n    try:\n        for root, dirs, files in os.walk(search_dir):\n            dirs[:] = [d for d in dirs if not d.startswith('.') and d != '__pycache__']\n            for f in files:\n                if fnmatch.fnmatch(f.lower(), pattern.lower()):\n                    results.append(os.path.join(root, f))\n        if not results:\n            return {'ok': True, 'output': 'Файлы не найдены по паттерну: ' + pattern, 'files': [], 'error': ''}\n        text = 'Найдено ' + str(len(results)) + ' файлов:' + chr(10) + chr(10).join(results[:50])\n        return {'ok': True, 'output': text, 'files': results[:20], 'error': ''}\n    except Exception as e:\n        return {'ok': False, 'output': str(e), 'files': [], 'error': str(e)}"
)

_T['analyze_code'] = (
    'Анализ Python кода на ошибки и улучшения',
    "def run_tool(inputs):\n    import ast, sys, os\n    from pathlib import Path\n    code = inputs.get('code', '')\n    path = inputs.get('path', '')\n    output_dir = inputs.get('output_dir', '/tmp')\n    if path and os.path.exists(path):\n        code = open(path, encoding='utf-8', errors='replace').read()\n    if not code:\n        return {'ok': False, 'output': 'Нужен code или path', 'files': [], 'error': 'missing'}\n    issues = []\n    try:\n        ast.parse(code)\n        issues.append('Синтаксис: OK')\n    except SyntaxError as e:\n        issues.append('SyntaxError строка ' + str(e.lineno) + ': ' + str(e.msg))\n    lines = code.split(chr(10))\n    for i, l in enumerate(lines, 1):\n        if 'except:' in l or 'except Exception:' in l:\n            issues.append('Строка ' + str(i) + ': голый except — поймает всё')\n        if 'print(' in l and '#' not in l.split('print')[0]:\n            issues.append('Строка ' + str(i) + ': print() — убери в продакшене')\n    report = chr(10).join(issues) + chr(10) + chr(10) + 'Строк кода: ' + str(len(lines))\n    out = Path(output_dir) / 'analysis.txt'\n    out.write_text(report, encoding='utf-8')\n    return {'ok': True, 'output': report, 'files': [str(out)], 'error': ''}"
)

_T['data_aggregator'] = (
    'Агрегация и суммаризация данных',
    "def run_tool(inputs):\n    import json as _j, os\n    from pathlib import Path\n    data   = inputs.get('data', inputs.get('items', []))\n    action = inputs.get('action', 'summary').lower()\n    output_dir = inputs.get('output_dir', '/tmp')\n    if isinstance(data, str):\n        try: data = _j.loads(data)\n        except: data = data.split(chr(10))\n    if not isinstance(data, list): data = [data]\n    if action == 'count': result = {'count': len(data)}\n    elif action == 'unique': result = list(set(str(x) for x in data))\n    elif action == 'join': result = chr(10).join(str(x) for x in data)\n    else: result = {'count': len(data), 'first': data[:3] if data else [], 'last': data[-3:] if len(data) > 3 else []}\n    out_str = _j.dumps(result, ensure_ascii=False, indent=2) if not isinstance(result, str) else result\n    out = Path(output_dir) / 'aggregated.json'\n    out.write_text(out_str, encoding='utf-8')\n    return {'ok': True, 'output': out_str[:3000], 'files': [str(out)], 'error': ''}"
)

_T['dedup_tool'] = (
    'Удаление дублирующихся записей',
    "def run_tool(inputs):\n    import json as _j\n    from pathlib import Path\n    data   = inputs.get('data', inputs.get('items', []))\n    key    = inputs.get('key', '')\n    output_dir = inputs.get('output_dir', '/tmp')\n    if isinstance(data, str):\n        try: data = _j.loads(data)\n        except: data = [l.strip() for l in data.split(chr(10)) if l.strip()]\n    seen = set(); result = []\n    for item in data:\n        val = item.get(key, str(item)) if key and isinstance(item, dict) else str(item)\n        if val not in seen: seen.add(val); result.append(item)\n    out_str = _j.dumps(result, ensure_ascii=False, indent=2)\n    out = Path(output_dir) / 'deduped.json'\n    out.write_text(out_str, encoding='utf-8')\n    removed = len(data) - len(result)\n    return {'ok': True, 'output': 'Было: ' + str(len(data)) + ', стало: ' + str(len(result)) + ', убрано: ' + str(removed) + chr(10) + out_str[:2000], 'files': [str(out)], 'error': ''}"
)

_T['diff_tool'] = (
    'Сравнение двух текстов/файлов',
    "def run_tool(inputs):\n    import difflib, os\n    from pathlib import Path\n    a      = inputs.get('a', inputs.get('text1', inputs.get('old', '')))\n    b      = inputs.get('b', inputs.get('text2', inputs.get('new', '')))\n    path_a = inputs.get('path_a', inputs.get('file1', ''))\n    path_b = inputs.get('path_b', inputs.get('file2', ''))\n    output_dir = inputs.get('output_dir', '/tmp')\n    if path_a and os.path.exists(path_a): a = open(path_a, encoding='utf-8', errors='replace').read()\n    if path_b and os.path.exists(path_b): b = open(path_b, encoding='utf-8', errors='replace').read()\n    if not a or not b: return {'ok': False, 'output': 'Нужны a и b', 'files': [], 'error': 'missing'}\n    diff = list(difflib.unified_diff(a.splitlines(), b.splitlines(), lineterm=''))\n    diff_text = chr(10).join(diff[:200])\n    out = Path(output_dir) / 'diff.txt'\n    out.write_text(diff_text, encoding='utf-8')\n    return {'ok': True, 'output': diff_text[:3000] or 'Файлы идентичны', 'files': [str(out)], 'error': ''}"
)

_T['api_caller'] = (
    'Универсальный HTTP вызов к любому API',
    "def run_tool(inputs):\n    import urllib.request, urllib.parse, json as _j\n    url     = inputs.get('url', inputs.get('endpoint', '')).strip()\n    method  = inputs.get('method', 'GET').upper()\n    data    = inputs.get('data', inputs.get('body', inputs.get('payload', None)))\n    headers = inputs.get('headers', {})\n    params  = inputs.get('params', inputs.get('query_params', {}))\n    if not url: return {'ok': False, 'output': 'Нужен url', 'files': [], 'error': 'missing'}\n    if params and isinstance(params, dict):\n        url = url + ('&' if '?' in url else '?') + urllib.parse.urlencode(params)\n    body = None\n    if data is not None:\n        if isinstance(data, dict): body = _j.dumps(data).encode(); headers.setdefault('Content-Type', 'application/json')\n        else: body = str(data).encode()\n    try:\n        h = {'User-Agent': 'Mozilla/5.0', **headers}\n        req = urllib.request.Request(url, data=body, headers=h, method=method)\n        with urllib.request.urlopen(req, timeout=15) as r:\n            resp = r.read(100000).decode('utf-8', 'replace')\n        try: result = _j.dumps(_j.loads(resp), ensure_ascii=False, indent=2)[:4000]\n        except: result = resp[:4000]\n        return {'ok': True, 'output': result, 'files': [], 'error': ''}\n    except Exception as e:\n        return {'ok': False, 'output': str(e), 'files': [], 'error': str(e)}"
)

_T['send_mail'] = (
    'Отправить email через SMTP или Telegram уведомление',
    "def run_tool(inputs):\n    import smtplib, os\n    from email.mime.text import MIMEText\n    to      = inputs.get('to', inputs.get('email', '')).strip()\n    subject = inputs.get('subject', 'NEO Report')\n    body    = inputs.get('body', inputs.get('text', inputs.get('content', '')))\n    smtp    = inputs.get('smtp', os.environ.get('SMTP_HOST', 'smtp.gmail.com'))\n    port    = int(inputs.get('port', 587))\n    user    = inputs.get('user', os.environ.get('SMTP_USER', ''))\n    pwd     = inputs.get('password', os.environ.get('SMTP_PASS', ''))\n    if not to: return {'ok': False, 'output': 'Нужен email получателя (to)', 'files': [], 'error': 'missing'}\n    if not body: return {'ok': False, 'output': 'Нужен body', 'files': [], 'error': 'missing'}\n    if not user or not pwd:\n        note = 'Email не отправлен (нет SMTP_USER/SMTP_PASS в .env).' + chr(10) + 'Сохранён отчёт:'\n        return {'ok': False, 'output': note + chr(10) + str(body)[:500], 'files': [], 'error': 'no_credentials'}\n    try:\n        msg = MIMEText(str(body), 'plain', 'utf-8')\n        msg['Subject'] = str(subject)\n        msg['From']    = user\n        msg['To']      = to\n        with smtplib.SMTP(smtp, port) as s:\n            s.starttls(); s.login(user, pwd); s.send_message(msg)\n        return {'ok': True, 'output': 'Email отправлен на ' + to, 'files': [], 'error': ''}\n    except Exception as e:\n        return {'ok': False, 'output': str(e), 'files': [], 'error': str(e)}"
)

_T['telegram_notify'] = (
    'Отправить уведомление в Telegram',
    "def run_tool(inputs):\n    import urllib.request, urllib.parse, json as _j, os\n    token   = inputs.get('token', os.environ.get('BOT_TOKEN', os.environ.get('TELEGRAM_BOT_TOKEN', '')))\n    chat_id = inputs.get('chat_id', inputs.get('to', os.environ.get('TELEGRAM_CHAT_ID', '')))\n    text    = inputs.get('text', inputs.get('message', inputs.get('body', '')))\n    if not token: return {'ok': False, 'output': 'Нужен BOT_TOKEN в .env или в inputs', 'files': [], 'error': 'no_token'}\n    if not chat_id: return {'ok': False, 'output': 'Нужен chat_id', 'files': [], 'error': 'no_chat_id'}\n    if not text: return {'ok': False, 'output': 'Нужен text', 'files': [], 'error': 'missing'}\n    try:\n        url = 'https://api.telegram.org/bot' + token + '/sendMessage'\n        data = _j.dumps({'chat_id': chat_id, 'text': str(text)[:4000]}).encode()\n        req = urllib.request.Request(url, data=data, headers={'Content-Type': 'application/json'})\n        with urllib.request.urlopen(req, timeout=10) as r:\n            resp = _j.loads(r.read())\n        if resp.get('ok'): return {'ok': True, 'output': 'Отправлено в ' + str(chat_id), 'files': [], 'error': ''}\n        return {'ok': False, 'output': str(resp), 'files': [], 'error': str(resp)}\n    except Exception as e:\n        return {'ok': False, 'output': str(e), 'files': [], 'error': str(e)}"
)

