_T['tts_speak'] = (
    'Синтез речи: текст → MP3',
    "def run_tool(inputs):\n    import sys, os\n    from pathlib import Path\n    sys.path.insert(0, str(Path(__file__).parent.parent))\n    text = inputs.get('text', inputs.get('message', '')).strip()\n    output_dir = inputs.get('output_dir', '/tmp')\n    lang = inputs.get('lang', inputs.get('language', 'ru'))\n    voice = inputs.get('voice', '')\n    if not text: return {'ok': False, 'output': 'Нужен text', 'files': [], 'error': 'missing'}\n    out_path = str(Path(output_dir) / ('tts_' + str(abs(hash(text)) % 99999) + '.mp3'))\n    try:\n        from tts_engine import tts_generate\n        ok = tts_generate(text, out_path, lang=lang)\n        if ok and os.path.exists(out_path):\n            return {'ok': True, 'output': 'Озвучено: ' + out_path, 'files': [out_path], 'error': ''}\n    except Exception: pass\n    try:\n        import asyncio, edge_tts\n        vc = voice or ('ru-RU-DmitryNeural' if lang == 'ru' else 'en-US-ChristopherNeural')\n        async def _tts():\n            comm = edge_tts.Communicate(text, vc)\n            await comm.save(out_path)\n        asyncio.run(_tts())\n        if os.path.exists(out_path):\n            return {'ok': True, 'output': 'Озвучено (edge-tts): ' + out_path, 'files': [out_path], 'error': ''}\n    except Exception as e:\n        return {'ok': False, 'output': 'TTS недоступен: ' + str(e), 'files': [], 'error': str(e)}\n    return {'ok': False, 'output': 'TTS недоступен', 'files': [], 'error': 'no_tts'}"
)


def register_all(on_status=None, llm_generate_missing=False):
    """Регистрирует все встроенные инструменты NEO."""
    try:
        sys.path.insert(0, str(BASE_DIR))
        from agent_neo import register_tool, tool_exists
    except ImportError as e:
        if on_status: on_status("agent_neo недоступен: " + str(e))
        return {"registered": 0, "skipped": 0, "generated": 0, "failed": 0}
    registered = skipped = failed = 0
    for name, (desc, code) in _T.items():
        try:
            if tool_exists(name):
                skipped += 1
                continue
            register_tool(name, desc, code.strip(), builtin=True)
            registered += 1
            if on_status: on_status("  + " + name)
        except Exception as e:
            failed += 1
            if on_status: on_status("  ! " + name + ": " + str(e))
    msg = "NEO tools: +" + str(registered) + " / skip=" + str(skipped) + " / err=" + str(failed)
    if on_status: on_status(msg)
    return {"registered": registered, "skipped": skipped, "generated": 0, "failed": failed}


def test_all(on_status=None):
    """Тестирует все инструменты."""
    passed = []; failed = []
    try:
        sys.path.insert(0, str(BASE_DIR))
        from agent_neo import list_tools, sandbox_run
        for t in list_tools():
            ok, out, _ = sandbox_run(t["code"], {"output_dir": "/tmp"}, timeout=10)
            (passed if ok or "missing" in out.lower() else failed).append(t["name"])
    except Exception as e:
        failed.append(str(e))
    return {"passed": passed, "failed": failed}